  science_research: {
    name: "Wissenschaft und Forschung",
    description: "Wissenschaftliche Konzepte und Forschung",
    icon: Microscope,
    color: "from-cyan-500 to-blue-600",
    level: "advanced",
    words: [
      { id: "ge_sci_1", german: "Wissenschaft", english: "Science", difficulty: "easy", example: "Science uses systematic methods to understand the natural world through observation experimentation and evidence", exampleTranslation: "Wissenschaft nutzt systematische Methoden um die natürliche Welt durch Beobachtung Experimente und Beweise zu verstehen" },
      { id: "ge_sci_2", german: "Forschung", english: "Research", difficulty: "easy", example: "Scientific research advances knowledge by investigating questions and testing hypotheses through rigorous methods", exampleTranslation: "Wissenschaftliche Forschung erweitert Wissen indem sie Fragen untersucht und Hypothesen durch rigorose Methoden testet" },
      { id: "ge_sci_3", german: "Experiment", english: "Experiment", difficulty: "easy", example: "The controlled experiment tested the hypothesis using careful methodology and precise measurements throughout", exampleTranslation: "Das kontrollierte Experiment testete die Hypothese unter Verwendung sorgfältiger Methodologie und präziser Messungen durchgehend" },
      { id: "ge_sci_4", german: "Labor", english: "Laboratory", difficulty: "easy", example: "Scientists work in the laboratory conducting experiments analyzing data and making new discoveries daily", exampleTranslation: "Wissenschaftler arbeiten im Labor führen Experimente durch analysieren Daten und machen täglich neue Entdeckungen" },
      { id: "ge_sci_5", german: "Hypothese", english: "Hypothesis", difficulty: "easy", example: "A scientific hypothesis must be testable through experiments and capable of being proven false", exampleTranslation: "Eine wissenschaftliche Hypothese muss durch Experimente testbar und fähig sein als falsch bewiesen zu werden" },
      { id: "ge_sci_6", german: "Theorie", english: "Theory", difficulty: "easy", example: "Scientific theories explain natural phenomena based on extensive evidence and have been tested repeatedly", exampleTranslation: "Wissenschaftliche Theorien erklären Naturphänomene basierend auf umfangreichen Beweisen und wurden wiederholt getestet" },
      { id: "ge_sci_7", german: "Entdeckung", english: "Discovery", difficulty: "medium", example: "Major scientific discoveries have transformed human civilization from electricity to antibiotics and modern technology", exampleTranslation: "Große wissenschaftliche Entdeckungen haben die menschliche Zivilisation von Elektrizität bis Antibiotika und moderner Technologie transformiert" },
      { id: "ge_sci_8", german: "Molekül", english: "Molecule", difficulty: "medium", example: "Water molecules consist of two hydrogen atoms bonded to one oxygen atom forming the essential liquid", exampleTranslation: "Wassermoleküle bestehen aus zwei Wasserstoffatomen die an ein Sauerstoffatom gebunden sind und die essentielle Flüssigkeit bilden" },
      { id: "ge_sci_9", german: "Evolution", english: "Evolution", difficulty: "medium", example: "The theory of evolution explains how species change over time through natural selection and adaptation", exampleTranslation: "Die Evolutionstheorie erklärt wie Arten sich im Laufe der Zeit durch natürliche Selektion und Anpassung verändern" },
      { id: "ge_sci_10", german: "Daten", english: "Data", difficulty: "medium", example: "Scientific data must be collected analyzed and interpreted carefully to draw valid accurate conclusions", exampleTranslation: "Wissenschaftliche Daten müssen sorgfältig gesammelt analysiert und interpretiert werden um gültige genaue Schlussfolgerungen zu ziehen" },
      { id: "ge_sci_11", german: "Mikroskop", english: "Microscope", difficulty: "medium", example: "The powerful microscope allows scientists to observe cells bacteria and structures invisible to the naked eye", exampleTranslation: "Das leistungsstarke Mikroskop erlaubt Wissenschaftlern Zellen Bakterien und für das bloße Auge unsichtbare Strukturen zu beobachten" },
      { id: "ge_sci_12", german: "Genetik", english: "Genetics", difficulty: "medium", example: "Genetics studies heredity and variation explaining how traits are passed from parents to offspring through DNA", exampleTranslation: "Genetik studiert Vererbung und Variation und erklärt wie Eigenschaften durch DNA von Eltern an Nachkommen weitergegeben werden" },
      { id: "ge_sci_13", german: "Wie funktioniert das wissenschaftlich?", english: "How does this work scientifically?", difficulty: "hard", example: "How does this complex mechanism work scientifically? Please explain the underlying principles and processes in detail!", exampleTranslation: "Wie funktioniert dieser komplexe Mechanismus wissenschaftlich? Bitte erklären Sie die zugrunde liegenden Prinzipien und Prozesse ausführlich!" },
      { id: "ge_sci_14", german: "Wissenschaftliche Methode", english: "Scientific method", difficulty: "hard", example: "The scientific method includes observation hypothesis experimentation analysis and peer-reviewed conclusions ensuring objectivity!", exampleTranslation: "Die wissenschaftliche Methode beinhaltet Beobachtung Hypothese Experimentierung Analyse und von Fachkollegen geprüfte Schlussfolgerungen die Objektivität gewährleisten!" },
      { id: "ge_sci_15", german: "Bahnbrechende Forschung", english: "Groundbreaking research", difficulty: "hard", example: "Groundbreaking research pushes boundaries of knowledge discovering new phenomena and revolutionizing our understanding of the universe!", exampleTranslation: "Bahnbrechende Forschung verschiebt Wissensgrenzen entdeckt neue Phänomene und revolutioniert unser Verständnis des Universums!" }
    ]
  },

